${SEP}'1i static void *ec_modal(char *loc, char *cmd, char *arg)
{
	int beg = 0, end = 0, o1 = 0, o2 = -1;
	if (lbuf_len(xb) && ex_region(loc, &beg, &end, &o1, &o2))
		return xrerr;
	if (!*loc) {
		beg = 0;
		end = lbuf_len(xb);
	}
	modal_t *ms = emalloc(sizeof(modal_t));
	memset(ms->regs, 0, sizeof(ms->regs));
	rules = rules_ = ms->rules;
	dict = dict_ = ms->dict;
	bank_a = src_ = ms->bank_a;
	bank_b = dst_ = ms->bank_b;
	regs = ms->regs;
	stack = stack_ = ms->stack;
	flip = safe_offset = 0;
	cycles = 0x200000;
	/* load rules from lbuf range into src_ */
	char *ptr = src_;
	for (int i = beg; i < end; i++) {
		char *ln = lbuf_get(xb, i);
		if (ln) {
			ptr = mem_import(ln, ptr);
			if (ptr < src_ + sizeof(ms->bank_a) - 1)
				*ptr++ = ' ';
		}
	}
	/* append arg (initial tape) to src_ */
	if (*arg)
		ptr = mem_import(arg, ptr);
	/* trim trailing whitespace and null-terminate */
	while (ptr > src_ && *(ptr - 1) <= ' ')
		ptr--;
	*ptr = '\\0';
	/* rewrite loop */
	void *ret = NULL;
	while (rewrite()) {
		if (!--cycles) {
			ret = \"modal: rewrites exceeded\";
			break;
		}
	}
	free(ms);
	return ret;
}

