typedef struct {
	char *a, *b;
} rule;

typedef struct {
	rule rules[0x1000];
	char dict[0x8000];
	char bank_a[0x4000];
	char bank_b[0x4000];
	char *regs[0x100];
	char stack[0x10];
} modal_t;

static int flip, cycles, safe_offset;
static rule *rules, *rules_;
static char *dict, *dict_;
static char *bank_a, *bank_b, *src_, *dst_;
static char **regs, *stack, *stack_;

#define spacer(c) (c <= ' ' || c == '(' || c == ')')
#define chex(c) (0xf & (c - (c <= '9' ? '0' : 0x57)))

static char *copy(char *src, char *dst, int length)
{
	while (length--)
		*dst++ = *src++;
	return dst;
}

static char *walk(char *s)
{
	char c;
	int depth = 0;
	if (*s == '(') {
		while ((c = *s++)) {
			if (c == '(')
				depth++;
			if (c == ')')
				--depth;
			if (!depth)
				return s;
		}
	}
	while ((c = *s) && !spacer(c))
		s++;
	return s;
}

static int sint(char *s)
{
	char c = *s, *cap = walk(s);
	int r = 0, n = 1;
	if (c == '#') {
		s++;
		while ((c = *s) && s++ < cap)
			r = (r << 4) | chex(c);
		return r;
	}
	if (c == '-') {
		n = -1;
		s++;
	}
	while ((c = *s) && s++ < cap)
		r = r * 10 + c - '0';
	return r * n;
}

static void device_write(char *s)
{
	char **reg = regs + '0';
	if (!*reg)
		return;
	int hex = **reg == '#', acc = sint(*reg++);
	/* clang-format off */
	switch(*s) {
	case '+': while (*reg) acc += sint(*reg++); break;
	case '-': while (*reg) acc -= sint(*reg++); break;
	case '*': while (*reg) acc *= sint(*reg++); break;
	case '/': while (*reg) acc /= sint(*reg++); break;
	case '%': while (*reg) acc %= sint(*reg++); break;
	case '&': while (*reg) acc &= sint(*reg++); break;
	case '^': while (*reg) acc ^= sint(*reg++); break;
	case '|': while (*reg) acc |= sint(*reg++); break;
	case '=': while (*reg) acc = acc == sint(*reg++); break;
	case '!': while (*reg) acc = acc != sint(*reg++); break;
	case '>': while (*reg) acc = acc > sint(*reg++); break;
	case '<': while (*reg) acc = acc < sint(*reg++); break;
	}
	/* clang-format on */
	dst_ += snprintf(dst_, 0x10, hex ? \"#%x\" : \"%d\", acc);
}

static void write_reg(char r, char *reg)
{
	unsigned char c;
	char *cap;
	switch(r) {
	case ':':
		device_write(reg);
		return;
	case '^': /* op: join */
		cap = walk(reg);
		if (*reg == '(') reg++, --cap;
		while (reg < cap && (c = *reg++))
			if (!spacer(c))
				*dst_++ = c;
		return;
	case '.': /* op: unwrap */
		cap = walk(reg);
		if (*reg == '(') reg++, --cap;
		dst_ = copy(reg, dst_, cap - reg);
		return;
	case '*':; /* op: explode */
		int i, depth = 0;
		cap = walk(reg);
		if (*reg == '(' && reg[1] != ')') { /* tuple */
			reg++;
			while (reg < cap - 1) {
				while ((c = *reg) && !spacer(c))
					*dst_++ = c, reg++;
				*dst_++ = ' ', *dst_++ = '(', reg++, depth++;
			}
		} else /* token */
			while ((c = *reg++) && !spacer(c))
				*dst_++ = c, *dst_++ = ' ', *dst_++ = '(', depth++;
		for (i = 0; i < depth; i++) *dst_++ = ')';
		return;
	default:
		dst_ = copy(reg, dst_, walk(reg) - reg);
		return;
	}
}

static int write_tail(char *s, rule *r)
{
	while ((*dst_++ = *s++));
	*dst_ = 0;
	if ((flip = !flip))
		src_ = bank_b, dst_ = bank_a;
	else
		src_ = bank_a, dst_ = bank_b;
	return 1;
}

static int apply_rule(rule *r, char *s)
{
	unsigned char rid;
	char c, *a = r->a, *b = r->b, *origin = dst_, *reg;
	/* phase: clean regs */
	while (stack_ != stack)
		regs[(int)*(--stack_)] = 0;
	/* phase: match rule */
	while ((c = *a++)) {
		if (c == '?') {
			char *pcap = walk(s);
			if (pcap == s)
				return 0;
			rid = *a++;
			if ((reg = regs[rid])) { /* reg cmp */
				char *rcap = walk(reg), *pp = s;
				if (rcap - reg != pcap - pp)
					return 0;
				while (reg < rcap)
					if (*reg++ != *pp++)
						return 0;
			} else { /* reg set */
				regs[rid] = s;
				*stack_++ = rid;
			}
			s = pcap;
		} else if (c != *s++)
			return 0;
	}
	c = *s;
	if (!spacer(c))
		return 0;
	/* phase: write rule */
	while ((c = *b++))
		if (c == '?' && (rid = *b) && (reg = regs[rid]))
			write_reg(rid, reg), b++;
		else
			*dst_++ = c;
	if (dst_ == origin) {
		while (*s == ' ')
			s++;
		if (*s == ')' && *(dst_ - 1) == ' ')
			dst_--;
	}
	return write_tail(s, r);
}

static char *parse_frag(char **side, char *s)
{
	char c, *cap;
	while ((c = *s) && c == ' ') s++;
	if (c == ')' || (c == '<' && s[1] == '>') || (c == '>' && s[1] == '<')) {
		*side = dict_;
		*dict_++ = 0;
		return s;
	} else {
		cap = walk(s);
		*side = dict_;
		if (c == '(')
			dict_ = copy(s + 1, dict_, cap - s - 2);
		else
			dict_ = copy(s, dict_, cap - s);
		s = cap;
		*dict_++ = 0;
	}
	return s;
}

static rule *find_rule(char *s, char *cap)
{
	rule *r = rules;
	if (*s == '(') {
		s++;
		cap--;
	}
	while (r < rules_) {
		char *ss = s, *a = r->a;
		while (*ss++ == *a++)
			if (!*a && ss == cap)
				return r;
		r++;
	}
	return NULL;
}

static void remove_rule(rule *r)
{
	if (r < rules_ - 1) {
		char *memsrc = (r + 1)->a;
		int distance = (r + 1)->a - r->a;
		copy(memsrc, r->a, dict_ - memsrc);
		while (r < rules_ - 1) {
			rule *next = r + 1;
			r->a = next->a - distance;
			r->b = next->b - distance;
			r++;
		}
	}
	rules_--;
}

static int rewrite(void)
{
	char c, last = 0, *cap, *s = src_;
	while (*s == ' ')
		s++;
	while ((c = *s)) {
		if (c == '(' || spacer(last)) {
			rule *r;
			/* phase: undefine */
			if (c == '>' && s[1] == '<') {
				s += 2;
				while (*s == ' ')
					s++;
				cap = walk(s);
				r = find_rule(s, cap);
				if (r != NULL)
					remove_rule(r);
				while (*cap == ' ')
					cap++;
				return write_tail(cap, NULL);
			}
			/* phase: define */
			if (c == '<' && s[1] == '>') {
				r = rules_;
				s = parse_frag(&r->b, parse_frag(&r->a, s + 2));
				if (*r->a)
					rules_++;
				while (*s == ' ')
					s++;
				return write_tail(s, NULL);
			}
			/* phase: lambda */
			if (c == '?' && s[1] == '(') {
				char *d = dict_;
				cap = walk(s + 1);
				r = rules_;
				parse_frag(&r->b, parse_frag(&r->a, s + 2));
				s = cap;
				while (*s == ' ')
					s++;
				if (!*r->a || !apply_rule(r, s))
					write_tail(s, NULL);
				dict_ = d;
				return 1;
			}
			/* phase: exec */
			if (c == '(' && s[1] == '\$') {
				cap = walk(s);
				char *p = s + 2, *q = p;
				while (q < cap - 1 && *q != '(')
					q++;
				if (q == cap - 1) {
					char cmd[512];
					int len = (int)(cap - 1 - p);
					if (len > 0 && len < (int)sizeof(cmd) - 1) {
						memcpy(cmd, p, len);
						cmd[len] = '\\0';
						ex_exec(cmd);
					}
					while (*cap == ' ')
						cap++;
					return write_tail(cap, NULL);
				}
			}
			/* phase: match */
			for (r = rules; r < rules_; r++)
				if (apply_rule(r, s))
					return 1;
		}
		*dst_++ = last = c, s++;
	}
	*dst_++ = 0;
	return 0;
}

static char *mem_import(char *src, char *ptr)
{
	unsigned char c, last = 0;
	while ((c = (unsigned char)*src++)) {
		c = c <= 0x20 ? 0x20 : c;
		if (c == ' ' && last == '(') continue;
		if (c == ')' && last == ' ') ptr--;
		if (c == ' ' && last == ' ') ptr--;
		if (c == '(' && last != '?' && !spacer(last)) *ptr++ = ' ';
		if (last == ')' && !spacer(c)) *ptr++ = ' ';
		*ptr++ = last = c;
	}
	return ptr;
}
