+	if (!spacer(c))
+		return 0;
+	/* phase: write rule */
+	while ((c = *b++))
+		if (c == '?' && (rid = *b) && (reg = regs[rid]))
+			write_reg(rid, reg), b++;
+		else
+			*dst_++ = c;
+	if (dst_ == origin) {
+		while (*s == ' ')
+			s++;
+		if (*s == ')' && *(dst_ - 1) == ' ')
+			dst_--;
+	}
+	return write_tail(s, r);
+}
+
+static char *parse_frag(char **side, char *s)
+{
+	char c, *cap;
+	while ((c = *s) && c == ' ') s++;
+	if (c == ')' || (c == '<' && s[1] == '>') || (c == '>' && s[1] == '<')) {
+		*side = dict_;
+		*dict_++ = 0;
+		return s;
+	} else {
+		cap = walk(s);
+		*side = dict_;
+		if (c == '(')
+			dict_ = copy(s + 1, dict_, cap - s - 2);
+		else
+			dict_ = copy(s, dict_, cap - s);
+		s = cap;
+		*dict_++ = 0;
+	}
+	return s;
+}
+
+static rule *find_rule(char *s, char *cap)
+{
+	rule *r = rules;
+	if (*s == '(') {
+		s++;
+		cap--;
+	}
+	while (r < rules_) {
+		char *ss = s, *a = r->a;
+		while (*ss++ == *a++)
+			if (!*a && ss == cap)
+				return r;
+		r++;
+	}
+	return NULL;
+}
+
+static void remove_rule(rule *r)
+{
+	if (r < rules_ - 1) {
+		char *memsrc = (r + 1)->a;
+		int distance = (r + 1)->a - r->a;
+		copy(memsrc, r->a, dict_ - memsrc);
+		while (r < rules_ - 1) {
+			rule *next = r + 1;
+			r->a = next->a - distance;
+			r->b = next->b - distance;
+			r++;
+		}
+	}
+	rules_--;
+}
+
+static int rewrite(void)
+{
+	char c, last = 0, *cap, *s = src_;
+	while (*s == ' ')
+		s++;
+	while ((c = *s)) {
+		if (c == '(' || spacer(last)) {
+			rule *r;
+			/* phase: undefine */
+			if (c == '>' && s[1] == '<') {
+				s += 2;
+				while (*s == ' ')
+					s++;
+				cap = walk(s);
+				r = find_rule(s, cap);
+				if (r != NULL)
+					remove_rule(r);
+				while (*cap == ' ')
+					cap++;
+				return write_tail(cap, NULL);
+			}
+			/* phase: define */
+			if (c == '<' && s[1] == '>') {
+				r = rules_;
+				s = parse_frag(&r->b, parse_frag(&r->a, s + 2));
+				if (*r->a)
+					rules_++;
+				while (*s == ' ')
+					s++;
+				return write_tail(s, NULL);
+			}
+			/* phase: lambda */
+			if (c == '?' && s[1] == '(') {
+				char *d = dict_;
+				cap = walk(s + 1);
+				r = rules_;
+				parse_frag(&r->b, parse_frag(&r->a, s + 2));
+				s = cap;
+				while (*s == ' ')
+					s++;
+				if (!*r->a || !apply_rule(r, s))
+					write_tail(s, NULL);
+				dict_ = d;
+				return 1;
+			}
+			/* phase: exec */
+			if (c == '(' && s[1] == '$') {
+				cap = walk(s);
+				char *p = s + 2, *q = p;
+				while (q < cap - 1 && *q != '(')
+					q++;
+				if (q == cap - 1) {
+					char cmd[512];
+					int len = (int)(cap - 1 - p);
+					if (len > 0 && len < (int)sizeof(cmd) - 1) {
+						memcpy(cmd, p, len);
+						cmd[len] = '\0';
+						ex_exec(cmd);
+					}
+					while (*cap == ' ')
+						cap++;
+					return write_tail(cap, NULL);
+				}
+			}
+			/* phase: match */
+			for (r = rules; r < rules_; r++)
+				if (apply_rule(r, s))
+					return 1;
+		}
+		*dst_++ = last = c, s++;
+	}
+	*dst_++ = 0;
+	return 0;
+}
+
+static char *mem_import(char *src, char *ptr)
+{
+	unsigned char c, last = 0;
+	while ((c = (unsigned char)*src++)) {
+		c = c <= 0x20 ? 0x20 : c;
+		if (c == ' ' && last == '(') continue;
+		if (c == ')' && last == ' ') ptr--;
+		if (c == ' ' && last == ' ') ptr--;
+		if (c == '(' && last != '?' && !spacer(last)) *ptr++ = ' ';
+		if (last == ')' && !spacer(c)) *ptr++ = ' ';
+		*ptr++ = last = c;
+	}
+	return ptr;
+}
